def lambda_handler(event: dict[str, Any], context: Any) -> dict[str, Any]:
    """AWS Lambda entry-point behind API Gateway (REST or HTTP API v2).

    Routes
    ------
    OPTIONS /*          → CORS preflight
    GET /users          → list all users
    GET /users/{userId} → single user by id
    """
    logger.info("Received event: %s", json.dumps(event, default=str))

    http_method = (
        event.get("httpMethod")  # REST API
        or event.get("requestContext", {}).get("http", {}).get("method", "")
    ).upper()

    # --- Preflight --------------------------------------------------------
    if http_method == "OPTIONS":
        return _response(204, "", event)

    # Only GET is supported
    if http_method != "GET":
        return _response(405, {"error": "Method not allowed"}, event)

    # --- Routing ----------------------------------------------------------
    path = event.get("path") or event.get("rawPath") or "/"
    path_params = event.get("pathParameters") or {}

    # GET /users/{userId}
    if "userId" in path_params:
        raw_id = path_params["userId"]
        user_id = _validate_user_id(raw_id)
        if user_id is None:
            logger.warning("Invalid userId received: %s", raw_id)
            return _response(400, {"error": "Invalid user ID format"}, event)

        user = _get_user(user_id)
        if user is None:
            return _response(404, {"error": "User not found"}, event)

        return _response(200, {"data": user}, event)

    # GET /users
    if path.rstrip("/").endswith("/users") or path == "/":
        users = _list_users()
        return _response(200, {"data": users, "count": len(users)}, event)

    return _response(404, {"error": "Not found"}, event)


